<template>
  <div>
    <SpRouterView class="merchantList">
      <div class="action-container">
        <el-button type="primary" icon="ecx-icon icon-xinzeng" @click="addMerchant">
          新增商戶
        </el-button>
      </div>

      <SpFilterForm :model="formParams" @onSearch="onSearch" @onReset="onSearch">
        <SpFilterFormItem prop="merchant_name" label="商戶名稱:">
          <el-input v-model="formParams.merchant_name" placeholder="請輸入商戶名稱" />
        </SpFilterFormItem>
        <SpFilterFormItem prop="legal_name" label="聯絡人:">
          <el-input v-model="formParams.legal_name" placeholder="請輸入聯絡人" />
        </SpFilterFormItem>
        <SpFilterFormItem prop="legal_mobile" label="聯絡電話:">
          <el-input v-model="formParams.legal_mobile" placeholder="請輸入聯絡電話" />
        </SpFilterFormItem>
        <SpFilterFormItem prop="time_start" label="入駐時間:" size="max">
          <el-date-picker
            v-model="formParams.time_start"
            clearable
            type="datetimerange"
            align="right"
            format="yyyy-MM-dd HH:mm:ss"
            range-separator="至"
            start-placeholder="開始日期"
            end-placeholder="結束日期"
            prefix-icon="null"
            :default-time="defaultTime"
            :picker-options="pickerOptions"
          />
        </SpFilterFormItem>
      </SpFilterForm>

      <SpFinder
        ref="finder"
        no-selection
        :setting="setting"
        :hooks="{
          beforeSearch: beforeSearch,
          afterSearch: afterSearch
        }"
        url="/merchant/list"
      />
    </SpRouterView>
  </div>
</template>

<script>
import { setCommodityAudit, setMerchantsState } from '@/api/mall/marketing'
import { PICKER_DATE_OPTIONS } from '@/consts'
import { createSetting } from '@shopex/finder'
import moment from 'moment'
export default {
  data() {
    return {
      defaultTime: ['00:00:00', '23:59:59'],
      pickerOptions: PICKER_DATE_OPTIONS,
      formParams: {
        merchant_name: '',
        legal_name: '',
        legal_mobile: '',
        time_start: []
      },
      datapass_block: 0,
      setting: createSetting({
        columns: [
          { name: '商戶名稱', key: 'merchant_name' },
          { name: '聯絡人', key: 'legal_name' },
          { name: '聯絡電話', key: 'legal_mobile' },
          {
            name: '入駐時間',
            key: 'created',
            formatter: (h, { created }) => {
              return moment(created * 1000).format('YYYY-MM-DD HH:mm:ss')
            }
          },
          {
            name: '商品審核（商戶商家商品是否需通過平台審核）',
            key: 'audit_goods',
            width: '100px',
            render: (h, { row }) =>
              h(
                'el-button',
                {
                  class: 'yahh',
                  props: { type: 'text' },
                  on: {
                    click: () => {
                      this.fnAffirm(row)
                    }
                  }
                },
                [
                  h('span', { class: 'aaa' }, row.audit_goods ? ' 是 ' : ' 否 '),
                  h('i', { class: 'el-icon-s-tools' }, '')
                ]
              ),

            renderHeader() {
              return (
                <div>
                  <span>商品審核 </span>
                  <el-tooltip
                    class='item'
                    effect='light'
                    content='商戶上架商品是否需通過平台審核'
                    placement='top-start'
                  >
                    {/* <span slot='content'>
                      商戶商家商品是否<br/>需通過平台審核
                      </span> */}
                    <i class='el-icon-question'></i>
                  </el-tooltip>
                </div>
              )
            }
          }
        ],
        actions: [
          {
            name: '詳情',
            key: 'detail',
            type: 'button',
            buttonType: 'text',
            action: {
              type: 'link',
              handler: async (val) => {
                this.$router.push({
                  path: this.matchHidePage('editor'),
                  query: { type: 'detail', merchantId: val[0].id }
                })
              }
            }
          },
          {
            name: '編輯',
            key: 'editor',
            type: 'button',
            buttonType: 'text',
            action: {
              type: 'link',
              handler: async (val) => {
                this.$router.push({
                  path: this.matchHidePage('editor'),
                  query: { type: 'edit', merchantId: val[0].id }
                })
              }
            },
            visible: () => {
              return this.datapass_block == 0
            }
          },
          {
            name: '停用',
            key: 'off',
            type: 'button',
            buttonType: 'text',
            action: {
              type: 'link',
              handler: async (val) => {
                this.fnMerchantsState(val, false)
              }
            },
            visible: (val) => {
              return !val.disabled
            }
          },
          {
            name: '開啟',
            key: 'off',
            type: 'button',
            buttonType: 'text',
            action: {
              type: 'link',
              handler: async (val) => {
                this.fnMerchantsState(val, true)
              }
            },
            visible: (val) => {
              return val.disabled
            }
          }
        ]
      })
    }
  },
  // 编辑或者删除后回调
  beforeRouteUpdate(to, from, next) {
    next()
    if (to.path.indexOf('editor') === -1 && to.path.indexOf('details') === -1) {
      this.$refs.finder.refresh(true)
    }
  },
  methods: {
    onSearch() {
      this.$refs.finder.refresh(true)
    },
    beforeSearch(params) {
      return {
        ...params,
        ...this.formParams
      }
    },
    afterSearch({ data }) {
      const { datapass_block } = data.data
      this.datapass_block = datapass_block
    },
    fnAffirm(row) {
      const message = row.audit_goods
        ? '關閉後商戶商品上架時無需審核，請確認是否關閉'
        : '開啟後商戶商品上架時需要審核，請確認是否開啟'
      this.$confirm(message, '通知消息', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning',
        center: true
      }).then(async () => {
        const result = await setCommodityAudit({ audit_goods: !row.audit_goods }, row.id)
        if (result.data.data.status) {
          this.$message({
            type: 'success',
            message: '更新成功!'
          })
          this.$refs.finder.refresh(true)
        }
      })
      console.log(row)
    },
    fnMerchantsState(row, status) {
      const id = row[0].id
      const message = status
        ? '開啟後且該商戶及其關聯店鋪的帳號可登錄商家端以及店鋪端，該商戶及其關聯店鋪在小程序顯示，請確認是否開啟。'
        : '停用後該商戶及其關聯店鋪不在小程序顯示，且該商戶及其關聯店鋪的帳號無法登錄商家端以及店鋪端，請確認是否停用該商戶。'
      this.$confirm(message, '通知消息', {
        confirmButtonText: '確定',
        cancelButtonText: '取消',
        type: 'warning',
        center: true
      }).then(async () => {
        const result = await setMerchantsState({ disabled: !status }, id)
        if (result.data.data.status) {
          this.$message({
            type: 'success',
            message: '更新成功!'
          })
          this.$refs.finder.refresh(true)
        }
      })
    },
    addMerchant() {
      this.$router.push({ path: this.matchHidePage('editor'), query: { type: 'add' } })
    }
  }
}
</script>

<style lang="scss">
.merchantList {
  .yahh {
    color: #409eff;
  }
}
</style>
